    paddingHorizontal: 12,
  },

  filesContainer: {
    marginTop: 6,
  },
  imageWrapper: {
    marginBottom: 6,
    borderRadius: 8,
    overflow: 'hidden',
    backgroundColor: '#222529',
    alignSelf: 'flex-start',
    borderWidth: 1,
    borderColor: '#383838',
  },
  imageAttachment: {
    borderRadius: 8,
  },
  imageCaption: {
    color: '#ABABAD',
    fontSize: 12,
    paddingHorizontal: 8,
    paddingVertical: 4,
  },
  fileCard: {
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: '#222529',
    borderRadius: 8,
    borderWidth: 1,
    borderColor: '#383838',
    padding: 10,
    marginBottom: 6,
    alignSelf: 'flex-start',
    minWidth: 200,
  },
  fileIcon: {
    width: 36,
    height: 36,
    borderRadius: 6,
    backgroundColor: '#383838',
